:root {
  --bg-card: #1a1d2e;
  --bg-row: #242740;
  --bg-row-hover: #2c3052;
  --border-card: #2e3250;
  --text-primary: #ffffff;
  --text-secondary: #8b90b8;
  --text-label: #5c6180;
  --accent-btc: #f7931a;
  --accent-eth: #627eea;
  --accent-sol: #9945ff;
  --accent-dot: #e6007a;
  --color-positive: #22c98e;
  --color-negative: #f04f63;
  --bar-track: #2e3250;
  --bar-btc: #f7931a;
  --bar-eth: #627eea;
  --bar-sol: #9945ff;
  --bar-dot: #e6007a;
  --footer-bg: #14162a;
  --divider: #2e3250;
}

.portfolio {
  width: 500px;
  background: var(--bg-card);
  border: 1px solid var(--border-card);
  border-radius: 16px;
  overflow: hidden;
  margin: 0 auto;
}

.portfolio-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 24px 16px;
  border-bottom: 1px solid var(--border-card);
}

.portfolio-title {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.portfolio-label {
  font-size: 12px;
  font-weight: 500;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.portfolio-value {
  font-size: 26px;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.1;
}

.portfolio-change {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 6px 12px;
  border-radius: 20px;
  font-size: 14px;
  font-weight: 600;
}

.portfolio-change.positive {
  background: rgba(34, 201, 142, 0.15);
  color: var(--color-positive);
}

.change-arrow {
  font-size: 10px;
}

.coin-list {
  display: flex;
  flex-direction: column;
  padding: 10px 16px;
  gap: 6px;
}

.coin-row {
  display: grid;
  grid-template-columns: 40px 100px 1fr 110px;
  align-items: center;
  gap: 12px;
  background: var(--bg-row);
  border-radius: 10px;
  padding: 10px 14px;
}

.coin-icon {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
}

.coin-icon.btc { background: var(--accent-btc); }
.coin-icon.eth { background: var(--accent-eth); }
.coin-icon.sol { background: var(--accent-sol); }
.coin-icon.dot { background: var(--accent-dot); }

.coin-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.coin-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.coin-ticker {
  font-size: 12px;
  color: var(--text-secondary);
  font-weight: 400;
}

.coin-bar-wrap {
  height: 6px;
  background: var(--bar-track);
  border-radius: 3px;
  overflow: hidden;
}

.coin-row:nth-child(1) .coin-bar { background: var(--bar-btc); }
.coin-row:nth-child(2) .coin-bar { background: var(--bar-eth); }
.coin-row:nth-child(3) .coin-bar { background: var(--bar-sol); }
.coin-row:nth-child(4) .coin-bar { background: var(--bar-dot); }

.coin-bar {
  height: 100%;
  border-radius: 3px;
}

.coin-stats {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 2px;
}

.coin-price {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.coin-change {
  font-size: 12px;
  font-weight: 500;
}

.coin-change.positive { color: var(--color-positive); }
.coin-change.negative { color: var(--color-negative); }

.portfolio-footer {
  display: flex;
  align-items: center;
  justify-content: space-around;
  background: var(--footer-bg);
  padding: 14px 24px;
  border-top: 1px solid var(--border-card);
}

.footer-stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.footer-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--text-label);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.footer-val {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.footer-divider {
  width: 1px;
  height: 28px;
  background: var(--divider);
}
